	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isInternalIP checks if an IP address belongs to internal/private networks
func isInternalIP(host string) bool {
	// First, try to parse as IP address
	if ip := net.ParseIP(host); ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsUnspecified()
	}

	// Check for localhost or internal domain patterns
	lowerHost := strings.ToLower(host)
	if strings.HasSuffix(lowerHost, ".local") ||
		strings.HasSuffix(lowerHost, ".internal") ||
		strings.Contains(lowerHost, "localhost") ||
		strings.Contains(lowerHost, "127.") ||
		strings.Contains(lowerHost, "192.168.") ||
		strings.Contains(lowerHost, "10.") ||
		strings.Contains(lowerHost, "172.16.") ||
		strings.Contains(lowerHost, "172.17.") ||
		strings.Contains(lowerHost, "172.18.") ||
		strings.Contains(lowerHost, "172.19.") ||
		strings.Contains(lowerHost, "172.20.") ||
		strings.Contains(lowerHost, "172.21.") ||
		strings.Contains(lowerHost, "172.22.") ||
		strings.Contains(lowerHost, "172.23.") ||
		strings.Contains(lowerHost, "172.24.") ||
		strings.Contains(lowerHost, "172.25.") ||
		strings.Contains(lowerHost, "172.26.") ||
		strings.Contains(lowerHost, "172.27.") ||
		strings.Contains(lowerHost, "172.28.") ||
		strings.Contains(lowerHost, "172.29.") ||
		strings.Contains(lowerHost, "172.30.") ||
		strings.Contains(lowerHost, "172.31.") {
		return true
	}

	// Resolve hostname to check IP
	addrs, err := net.LookupHost(host)
	if err != nil {
		// If we can't resolve, assume it's external (safer)
		return false
	}

	// Check all resolved IPs
	for _, addr := range addrs {
		if ip := net.ParseIP(addr); ip != nil {
			if ip.IsPrivate() || ip.IsLoopback() || ip.IsUnspecified() {
				return true
			}
		}
	}

	return false
}

