func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	// Validate webhook URL is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Send test request to validate webhook URL
	if err := validateWebhookURL(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook validation failed: %v", err),
			URL:     config.WebhookURL,
		})
	}

	// Save configuration (in-memory for this example)
	configuredWebhookURL = config.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
		URL:     config.WebhookURL,
	})
}

// validateWebhookURL sends a GET request to validate the webhook URL
func validateWebhookURL(url string) error {
	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context
	req, err := http.NewRequestWithContext(context.Background(), "GET", url, nil)
	if err != nil {
		return fmt.Errorf("invalid URL: %w", err)
	}

	// Send test request
	resp, err := client.Do(req)
	if err != nil {
		return fmt.Errorf("connection failed: %w", err)
	}
	defer resp.Body.Close()

	// Check for successful response (2xx status codes)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("received non-2xx status code: %d", resp.StatusCode)
	}

	return nil
}

func main() {
	// Initialize Fiber app
	app := fiber.New(fiber.Config{
		JSONEncoder: json.Marshal,
		JSONDecoder: json.Unmarshal,
	})

	// Register webhook configuration endpoint
	app.Post("/webhook/configure", ConfigureWebhook)

	// Optional: Add endpoint to view current configuration
	app.Get("/webhook/configured", func(ctx *fiber.Ctx) error {
		return ctx.JSON(fiber.Map{
			"configured_url": configuredWebhookURL,
		})
	})

	// Start server
	fmt.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}

