// WebhookConfig represents the request payload for configuring a webhook
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response structure
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

var configuredWebhookURL string // Simple in-memory storage for demonstration

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON payload",
		})
	}

	// Validate webhook URL format (basic check)
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Send test request to validate the webhook URL
	client := &http.Client{
		Timeout: 3 * time.Second, // 3-second timeout as required
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration (in-memory for this example)
	configuredWebhookURL = config.WebhookURL

	// Return success response
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

// GetWebhookConfig is a helper endpoint to view the current configuration (optional)
func GetWebhookConfig(ctx *fiber.Ctx) error {
	return ctx.JSON(fiber.Map{
		"configured_webhook_url": configuredWebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Define routes
	app.Post("/configure-webhook", ConfigureWebhook)
	app.Get("/webhook-config", GetWebhookConfig) // Optional endpoint for verification

	// Start server
	fmt.Println("Server starting on :8080")
	app.Listen(":8080")
}

