		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid JSON payload",
		})
	}

	// Validate webhook URL is provided
	if config.URL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Send test request to validate webhook URL
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.URL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if response status is acceptable (2xx or 3xx)
	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	webhookStore.mu.Lock()
	webhookStore.urls[config.URL] = true
	webhookStore.mu.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured successfully",
		"data": fiber.Map{
			"webhook_url": config.URL,
			"test_status": resp.StatusCode,
		},
	})
}

// GetConfiguredWebhooks returns all configured webhook URLs
func GetConfiguredWebhooks(ctx *fiber.Ctx) error {
	webhookStore.mu.RLock()
	defer webhookStore.mu.RUnlock()

	urls := make([]string, 0, len(webhookStore.urls))
	for url := range webhookStore.urls {
		urls = append(urls, url)
	}

	return ctx.JSON(fiber.Map{
		"status": "success",
		"data":   urls,
	})
}

func main() {
	app := fiber.New()

	// Configure JSON middleware
	app.Use(func(c *fiber.Ctx) error {
		c.Accepts("application/json")
		return c.Next()
	})

	// Routes
	app.Post("/webhook/configure", ConfigureWebhook)
	app.Get("/webhooks", GetConfiguredWebhooks)

	// Start server
	fmt.Println("Server starting on :3000")
	app.Listen(":3000")
}

