			if len(via) >= 10 {
				return fmt.Errorf("too many redirects")
			}
			host := req.URL.Hostname()
			if isPrivateIP(net.ParseIP(host)) || isLocalhost(host) {
				return fmt.Errorf("redirect to private network blocked")
			}
			return nil
		},
		Transport: &http.Transport{
			DisableKeepAlives: true,
			MaxIdleConns:      1,
		},
	}

	// Create context with timeout for the request
	reqCtx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	// Create GET request with context
	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to create request: %v", err),
		})
	}

	// Set safe headers only
	httpReq.Header.Set("User-Agent", "Webhook-Validator/1.0")
	httpReq.Header.Set("Accept", "application/json")

	// Send test request to webhook URL
	resp, err := client.Do(httpReq)
	if err != nil {
		// Check if error is due to timeout
		if err == context.DeadlineExceeded {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Webhook URL request timeout",
			})
		}
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", sanitizeError(err)),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
