	})
}

// validateHostname checks if hostname is safe (not localhost or private IP)
func validateHostname(hostname string) error {
	// Check for localhost
	if isLocalhost(hostname) {
		return fmt.Errorf("localhost not allowed")
	}

	// Try to resolve IP
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("cannot resolve hostname")
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("private IP address not allowed")
		}
	}

	return nil
}

// isPrivateIP checks if an IP address is in private ranges
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Check IPv4 private ranges
	if ip.To4() != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsUnspecified()
	}

	// Check IPv6 private ranges
	return ip.IsPrivate() || ip.IsLoopback() || ip.IsUnspecified()
}

// isLocalhost checks if hostname refers to localhost
func isLocalhost(hostname string) bool {
	hostname = strings.ToLower(hostname)
	return hostname == "localhost" ||
		strings.HasSuffix(hostname, ".localhost") ||
		strings.HasSuffix(hostname, ".local")
}

// sanitizeError removes sensitive information from error messages
func sanitizeError(err error) string {
	errStr := err.Error()
	// Remove any IP addresses from error messages
	// This is a basic sanitization - in production you might want more robust sanitization
	return errStr
}

