// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	// Validate URL format (basic check)
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Send test request with 3-second timeout
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Test request failed: %v", err),
			URL:     config.WebhookURL,
		})
	}
	defer resp.Body.Close()

	// Check for successful response (2xx status codes)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Test request returned non-2xx status: %d", resp.StatusCode),
			URL:     config.WebhookURL,
		})
	}

	// Save configuration (in-memory example)
