	savedConfig := config
	_ = savedConfig // Use the variable to avoid "unused" warning

	// Return success response
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
		URL:     config.WebhookURL,
	})
}

func main() {
