			"success": false,
			"error":   "Webhook URL cannot point to internal/private network",
		})
	}

	// Security: Validate URL length to prevent DoS
	if len(req.WebhookURL) > 2000 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL is too long",
		})
	}

	// Create a custom HTTP client with timeout and redirect limits
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Security: Limit redirects to prevent infinite loops
			if len(via) >= 5 {
				return fmt.Errorf("too many redirects")
			}
			// Security: Validate redirect URLs
			if isPrivateIP(req.URL.Hostname()) {
				return fmt.Errorf("redirect to private network blocked")
			}
			return nil
		},
	}

	// Send test GET request to webhook URL
	reqURL := strings.TrimSpace(req.WebhookURL)
	httpReq, err := http.NewRequest("GET", reqURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	// Security: Set safe headers
	httpReq.Header.Set("User-Agent", "Webhook-Tester/1.0")
	httpReq.Header.Set("Accept", "application/json")

	resp, err := client.Do(httpReq)
	if err != nil {
		// Security: Don't expose internal error details
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL",
		})
	}
	defer resp.Body.Close()

