	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isPrivateIP checks if a hostname resolves to private/internal IP address
func isPrivateIP(hostname string) bool {
	// Security: Block common private IP ranges and localhost
	privateIPPrefixes := []string{
		"127.", "10.", "172.16.", "172.17.", "172.18.", "172.19.",
		"172.20.", "172.21.", "172.22.", "172.23.", "172.24.", "172.25.",
		"172.26.", "172.27.", "172.28.", "172.29.", "172.30.", "172.31.",
		"192.168.", "169.254.", "::1", "fc00:", "fd00:", "fe80:",
	}

	// Remove port if present
	hostname = strings.Split(hostname, ":")[0]

	// Check against private IP prefixes
	for _, prefix := range privateIPPrefixes {
		if strings.HasPrefix(hostname, prefix) {
			return true
		}
	}

	// Check for localhost
	if hostname == "localhost" || strings.HasSuffix(hostname, ".local") {
		return true
	}

	return false
}

