import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type WebhookConfigResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

var configuredWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Validate webhook URL by sending test request
	httpClient := http.Client{
		Timeout: 3 * time.Second,
	}

	httpReq, err := http.NewRequestWithContext(context.Background(), "GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Invalid URL: %v", err),
		})
	}

	resp, err := httpClient.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Test request returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration
	configuredWebhookURL = req.WebhookURL

	return ctx.JSON(WebhookConfigResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional: Add a route to check current configuration
	app.Get("/current-webhook", func(c *fiber.Ctx) error {
		return c.JSON(fiber.Map{
			"configured_webhook_url": configuredWebhookURL,
		})
	})

	app.Listen(":3000")
}

