	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Perform security validation on the URL
	if err := validateURLSecurity(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Create a custom HTTP client with security settings
	client := &http.Client{
		Timeout: 3 * time.Second,
		Transport: &http.Transport{
			// Disable keep-alives to prevent connection exhaustion
			DisableKeepAlives: true,
			// Limit response size
			ResponseHeaderTimeout: 2 * time.Second,
		},
		// Prevent following redirects to avoid SSRF chains
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Create a context with timeout for the request
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP request with context
	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	// Set secure headers
	httpReq.Header.Set("User-Agent", "Webhook-Validator/1.0")
	httpReq.Header.Set("Accept", "application/json")

	// Send test request to webhook URL
	resp, err := client.Do(httpReq)
	if err != nil {
		// Generic error message to avoid information leakage
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL",
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL validation failed",
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance
	// Note: Use parameterized queries to prevent SQL injection when saving to database

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

