// isPrivateIP checks if a hostname resolves to a private/internal IP address
func isPrivateIP(hostname string) bool {
	// Check for localhost or loopback addresses
	if hostname == "localhost" || strings.HasSuffix(hostname, ".localhost") {
		return true
	}

	// Check for common private network patterns
	privatePrefixes := []string{
		"10.", "172.16.", "172.17.", "172.18.", "172.19.",
		"172.20.", "172.21.", "172.22.", "172.23.", "172.24.",
		"172.25.", "172.26.", "172.27.", "172.28.", "172.29.",
		"172.30.", "172.31.", "192.168.", "127.", "169.254.",
		"::1", "fc00:", "fd00:", "fe80:",
	}

	for _, prefix := range privatePrefixes {
		if strings.HasPrefix(hostname, prefix) {
			return true
		}
	}

	// Check for IPv6 loopback and link-local
	if strings.Contains(hostname, "[::1]") || strings.Contains(hostname, "[fe80:") {
		return true
	}

	return false
}

