			"success": false,
			"message": "Webhook URL validation failed",
			"error":   err.Error(),
		})
	}

	// Save configuration
	appState.mu.Lock()
	appState.webhookURL = config.URL
	appState.lastConfigured = time.Now()
	appState.mu.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"data": fiber.Map{
			"webhook_url":     config.URL,
			"configured_at":   time.Now().Format(time.RFC3339),
			"validation_time": "3s",
		},
	})
}

// validateWebhookURL sends a test GET request to validate the URL
func validateWebhookURL(url string) error {
	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context timeout
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return fmt.Errorf("failed to create request: %w", err)
	}

	// Send test request
	resp, err := client.Do(req)
	if err != nil {
		return fmt.Errorf("failed to reach webhook URL: %w", err)
	}
	defer resp.Body.Close()

	// Check for successful response (2xx status code)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("webhook returned non-2xx status: %s", resp.Status)
	}

	return nil
}

// GetWebhookConfig returns the current webhook configuration
func GetWebhookConfig(ctx *fiber.Ctx) error {
	appState.mu.RLock()
	defer appState.mu.RUnlock()

	return ctx.JSON(fiber.Map{
		"success": true,
		"data": fiber.Map{
			"webhook_url":     appState.webhookURL,
			"last_configured": appState.lastConfigured.Format(time.RFC3339),
		},
	})
}

// HealthCheck returns application health status
func HealthCheck(ctx *fiber.Ctx) error {
	return ctx.JSON(fiber.Map{
		"status":  "ok",
		"service": "webhook-configurator",
		"time":    time.Now().Format(time.RFC3339),
	})
}

func main() {
	// Create new Fiber app
	app := fiber.New(fiber.Config{
		JSONEncoder: json.Marshal,
		JSONDecoder: json.Unmarshal,
	})

	// Setup routes
	app.Post("/webhook/configure", ConfigureWebhook)
	app.Get("/webhook/config", GetWebhookConfig)
	app.Get("/health", HealthCheck)

	// Start server
	fmt.Println("Starting server on :8080")
	if err := app.Listen(":8080"); err != nil {
		panic(fmt.Sprintf("Failed to start server: %v", err))
	}
}

