// isPrivateIP checks if an IP address is private/local
func isPrivateIP(ip net.IP) bool {
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			ip4[0] == 127
	}
	// IPv6 private ranges
	return ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() ||
		strings.HasPrefix(ip.String(), "fd") || strings.HasPrefix(ip.String(), "fc")
}

// validateURL checks if URL is safe (not private/local)
func validateURL(u *url.URL) error {
	// Resolve host to IP addresses
	ips, err := net.LookupIP(u.Hostname())
	if err != nil {
		return fmt.Errorf("could not resolve host: %v", err)
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP %s is not allowed", ip.String())
		}
	}
