}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// SSRF protection: validate URL is not pointing to private/local resources
	if err := validateURL(parsedURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Invalid webhook URL: %v", err),
		})
	}

	// Create a custom HTTP client with timeout and redirect restrictions
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit redirects to prevent redirect loops and SSRF
			if len(via) >= 5 {
				return fmt.Errorf("too many redirects")
			}

			// Validate redirect URL
			if err := validateURL(req.URL); err != nil {
				return fmt.Errorf("redirect to private URL blocked: %v", err)
			}
			return nil
		},
	}

	// Prepare test payload as query parameter for GET request
	testPayload := webhookTestPayload{
		Message: "Webhook configuration test",
	}
	jsonPayload, err := json.Marshal(testPayload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test payload",
		})
	}

	// Create GET request with query parameters instead of POST body
	reqURL := parsedURL.String()
	// Add test payload as query parameter
	if strings.Contains(reqURL, "?") {
		reqURL += "&test=" + url.QueryEscape(string(jsonPayload))
	} else {
		reqURL += "?test=" + url.QueryEscape(string(jsonPayload))
	}

	// Create request with context for timeout control
	httpReq, err := http.NewRequestWithContext(context.Background(), "GET", reqURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create request",
		})
	}

	// Set User-Agent header
	httpReq.Header.Set("User-Agent", "Webhook-Validator/1.0")

	// Send test request to webhook URL
	resp, err := client.Do(httpReq)
	if err != nil {
		// Check if error is due to timeout
		if netErr, ok := err.(net.Error); ok && netErr.Timeout() {
			return ctx.Status(fiber.StatusRequestTimeout).JSON(fiber.Map{
				"success": false,
				"error":   "Webhook URL request timeout",
			})
		}
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

