	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	// Resolve host to IP addresses
	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("empty host")
	}

	// Check for localhost
	if strings.EqualFold(host, "localhost") {
		return fmt.Errorf("localhost is not allowed")
	}

	// Resolve IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve host")
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("private IP addresses are not allowed")
		}
	}

	return nil
}

// safeHTTPClient creates an HTTP client with security restrictions
func safeHTTPClient() *http.Client {
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			// Split host and port
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, fmt.Errorf("invalid address format")
			}

			// Resolve to check if it's a private IP
			ip := net.ParseIP(host)
			if ip == nil {
				ips, err := net.LookupIP(host)
				if err != nil {
					return nil, fmt.Errorf("failed to resolve host")
				}
				for _, resolvedIP := range ips {
					if isPrivateIP(resolvedIP) {
						return nil, fmt.Errorf("private IP addresses are not allowed")
					}
				}
			} else if isPrivateIP(ip) {
				return nil, fmt.Errorf("private IP addresses are not allowed")
			}

			return dialer.DialContext(ctx, network, addr)
		},
		DisableKeepAlives:   true,
		MaxIdleConns:        0,
		MaxIdleConnsPerHost: 0,
	}

	return &http.Client{
		Transport: transport,
		Timeout:   3 * time.Second,
	}
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Perform security validation
	if err := validateURLSecurity(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Create a secure HTTP client
	client := safeHTTPClient()

	// Send test request to webhook URL using GET
	// Note: GET requests don't typically have a body, but we'll send query parameters instead
	parsedURL, _ := url.Parse(req.WebhookURL)
	q := parsedURL.Query()
	testPayload := webhookTestPayload{
		Message: "Webhook configuration test",
	}
	jsonPayload, err := json.Marshal(testPayload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test payload",
		})
	}
	q.Set("test", string(jsonPayload))
	parsedURL.RawQuery = q.Encode()

	resp, err := client.Get(parsedURL.String())
	if err != nil {
		// Don't expose internal error details to the client
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to send test request to webhook URL",
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

