		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration (in-memory storage for this example)
	configuredWebhookURL = config.WebhookURL

	// Return success response
	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Route for configuring webhook
	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional: Route to check current configuration
	app.Get("/current-webhook", func(ctx *fiber.Ctx) error {
		if configuredWebhookURL == "" {
			return ctx.JSON(map[string]interface{}{
				"configured": false,
				"message":    "No webhook configured",
			})
		}
		return ctx.JSON(map[string]interface{}{
			"configured": true,
			"url":        configuredWebhookURL,
		})
	})

	// Start server on port 3000
	app.Listen(":3000")
}

